const email = $input.first().json;
const attachments = [];

// n8n Gmail trigger stores attachments as attachment_0, attachment_1, etc.
for (let i = 0; ; i++) {
  const key = `attachment_${i}`;
  if (!email[key]) break;
  attachments.push(email[key]);
}

const csvAttachment = attachments.find(a =>
  (a.name || '').toLowerCase().endsWith('.csv') ||
  (a.mimeType || '').includes('csv')
);

if (!csvAttachment) {
  throw new Error('No CSV attachment in email from: ' + (email.from || 'unknown'));
}

const csvContent = Buffer.from(csvAttachment.data, 'base64')
  .toString('utf-8')
  .replace(/^\uFEFF/, '')        // strip BOM
  .replace(/\r\n/g, '\n')
  .replace(/\r/g, '\n');

const lines = csvContent.split('\n').filter(l => l.trim());
if (lines.length < 2) throw new Error('CSV has no data rows');

function parseCSVLine(line) {
  const result = [];
  let current = '';
  let inQuotes = false;
  for (let i = 0; i < line.length; i++) {
    const ch = line[i];
    if (ch === '"') {
      if (inQuotes && line[i + 1] === '"') { current += '"'; i++; }
      else inQuotes = !inQuotes;
    } else if (ch === ',' && !inQuotes) {
      result.push(current.trim()); current = '';
    } else {
      current += ch;
    }
  }
  result.push(current.trim());
  return result;
}

const headers = parseCSVLine(lines[0]);
const rows = [];
for (let i = 1; i < lines.length; i++) {
  if (!lines[i].trim()) continue;
  const values = parseCSVLine(lines[i]);
  const row = {};
  headers.forEach((h, idx) => { row[h] = values[idx] || ''; });
  rows.push(row);
}

return [{ json: { rows, row_count: rows.length, filename: csvAttachment.name } }];

const clientId = $('Lookup Client').first().json.id;
const rows = $('Parse CSV Rows').first().json.rows;

const MAPPED_COLS = new Set([
  'Contact Name','Full Name','Name',
  'Email','Email Address',
  'Phone','Phone Number','Mobile','Cell',
  'Status','Assigned To','Agent','Agent Email',
  'Source','Lead Source',
  'Address','Property Address',
  'Created Date','Date Added'
]);

return rows
  .map(row => {
    const rawName = (row['Contact Name'] || row['Full Name'] || row['Name'] || '').trim();
    const emailRaw = (row['Email'] || row['Email Address'] || '').toLowerCase().trim();
    const rawPhone = (row['Phone'] || row['Phone Number'] || row['Mobile'] || row['Cell'] || '').replace(/[^\d]/g, '');
    const phone = rawPhone.length === 11 && rawPhone.startsWith('1') ? rawPhone.slice(1) : rawPhone;

    if (!emailRaw && !phone) return null;

    const metadata = {
      boldtrail_status:     row['Status'] || '',
      agent_email:          (row['Assigned To'] || row['Agent'] || row['Agent Email'] || '').trim(),
      lead_source:          (row['Source'] || row['Lead Source'] || '').trim(),
      property_address:     (row['Address'] || row['Property Address'] || '').trim(),
      boldtrail_created_at: (row['Created Date'] || row['Date Added'] || '').trim(),
    };
    Object.keys(row).forEach(k => {
      if (!MAPPED_COLS.has(k) && row[k]) metadata['raw_' + k] = row[k];
    });

    // Escape single quotes for safe SQL interpolation
    const safeName    = rawName.replace(/'/g, "''");
    const safeEmail   = emailRaw.replace(/'/g, "''");
    const safePhone   = phone.replace(/'/g, "''");
    const safeMeta    = JSON.stringify(metadata).replace(/'/g, "''");
    const emailVal    = safeEmail ? `'${safeEmail}'` : 'NULL';
    const phoneVal    = safePhone ? `'${safePhone}'` : 'NULL';

    const upsertQuery = `INSERT INTO leads (client_id, lead_name, email, phone, source, metadata)\nVALUES ('${clientId}', '${safeName}', ${emailVal}, ${phoneVal}, 'boldtrail', '${safeMeta}'::jsonb)\nON CONFLICT (email, phone) WHERE email IS NOT NULL AND phone IS NOT NULL\nDO UPDATE SET\n  lead_name  = EXCLUDED.lead_name,\n  metadata   = leads.metadata || EXCLUDED.metadata,\n  updated_at = NOW()`;

    return { json: { upsert_query: upsertQuery, client_id: clientId } };
  })
  .filter(Boolean);
